-- 스테이징: SQLite consolidated_data 미러 (샘플 적재용)
SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS=0;
DROP TABLE IF EXISTS staging_consolidated;
CREATE TABLE staging_consolidated (
  `id` BIGINT AUTO_INCREMENT PRIMARY KEY,
  `exported_at` TEXT NOT NULL,
  `날짜` TEXT,
  `작업지시번호` TEXT,
  `고객사` TEXT,
  `사업명` TEXT,
  `품명` TEXT,
  `품번` TEXT,
  `공정` TEXT,
  `고객사납품` TEXT,
  `자재입고수량` TEXT,
  `발주사양` TEXT,
  `폴더명` TEXT,
  `BOM파일명` TEXT,
  `발행리스트` TEXT
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

